import{_ as a,o as t,c as r,a4 as o}from"./chunks/framework.Bz0lZ1uX.js";const q=JSON.parse('{"title":"人物素材","description":"","frontmatter":{},"headers":[],"relativePath":"materials/人物素材/index.md","filePath":"materials/人物素材/index.md","lastUpdated":null}'),e={name:"materials/人物素材/index.md"},n=o('<h1 id="人物素材" tabindex="-1">人物素材 <a class="header-anchor" href="#人物素材" aria-label="Permalink to &quot;人物素材&quot;">​</a></h1><p>人物素材是议论文写作中最常用的论据类型之一。通过典型人物的事迹，可以有力地支撑论点。</p><h2 id="科学家类" tabindex="-1">科学家类 <a class="header-anchor" href="#科学家类" aria-label="Permalink to &quot;科学家类&quot;">​</a></h2><h3 id="屠呦呦-青蒿素的发现者" tabindex="-1">屠呦呦 - 青蒿素的发现者 <a class="header-anchor" href="#屠呦呦-青蒿素的发现者" aria-label="Permalink to &quot;屠呦呦 - 青蒿素的发现者&quot;">​</a></h3><p><strong>标签</strong>: #科学家 #诺贝尔奖 #坚持不懈 #中医药</p><p><strong>事迹</strong>: 屠呦呦带领团队从古代医书中获得灵感，经过数百次实验，最终成功提取青蒿素，拯救了数百万疟疾患者的生命。2015年获得诺贝尔生理学或医学奖，成为中国首位诺贝尔科学奖获得者。</p><p><strong>适用主题</strong>: 创新、坚持、传统与现代结合、女性力量、科研精神</p><h3 id="袁隆平-杂交水稻之父" tabindex="-1">袁隆平 - 杂交水稻之父 <a class="header-anchor" href="#袁隆平-杂交水稻之父" aria-label="Permalink to &quot;袁隆平 - 杂交水稻之父&quot;">​</a></h3><p><strong>标签</strong>: #科学家 #农业 #奉献 #粮食安全</p><p><strong>事迹</strong>: 袁隆平毕生致力于杂交水稻研究，使中国水稻产量大幅提高，为解决中国乃至世界粮食安全问题做出巨大贡献。他常说：&quot;人就像种子，要做一粒好种子。&quot;</p><p><strong>适用主题</strong>: 奉献、责任、科技创新、民生、梦想追求</p><h2 id="企业家类" tabindex="-1">企业家类 <a class="header-anchor" href="#企业家类" aria-label="Permalink to &quot;企业家类&quot;">​</a></h2><h3 id="任正非-华为创始人" tabindex="-1">任正非 - 华为创始人 <a class="header-anchor" href="#任正非-华为创始人" aria-label="Permalink to &quot;任正非 - 华为创始人&quot;">​</a></h3><p><strong>标签</strong>: #企业家 #科技创新 #危机意识 #自立自强</p><p><strong>事迹</strong>: 任正非44岁创业，带领华为从一家小型通信设备公司成长为全球领先的科技企业。面对外部压力，坚持自主研发，推出鸿蒙系统和麒麟芯片。</p><p><strong>适用主题</strong>: 自立自强、危机意识、长远眼光、民族企业、创新突破</p><h3 id="曹德旺-玻璃大王" tabindex="-1">曹德旺 - 玻璃大王 <a class="header-anchor" href="#曹德旺-玻璃大王" aria-label="Permalink to &quot;曹德旺 - 玻璃大王&quot;">​</a></h3><p><strong>标签</strong>: #企业家 #慈善 #实体经济 #工匠精神</p><p><strong>事迹</strong>: 曹德旺专注于汽车玻璃制造数十年，将福耀玻璃打造成全球知名品牌。他累计捐款超过160亿元，是中国慈善事业的标杆人物。</p><p><strong>适用主题</strong>: 专注、工匠精神、社会责任、实体经济、回馈社会</p><h2 id="文化类" tabindex="-1">文化类 <a class="header-anchor" href="#文化类" aria-label="Permalink to &quot;文化类&quot;">​</a></h2><h3 id="苏轼-豁达的人生态度" tabindex="-1">苏轼 - 豁达的人生态度 <a class="header-anchor" href="#苏轼-豁达的人生态度" aria-label="Permalink to &quot;苏轼 - 豁达的人生态度&quot;">​</a></h3><p><strong>标签</strong>: #文学家 #乐观 #逆境 #豁达</p><p><strong>事迹</strong>: 苏轼一生多次被贬，但始终保持乐观豁达的心态。在黄州写下&quot;大江东去，浪淘尽&quot;，在惠州写下&quot;日啖荔枝三百颗，不辞长作岭南人&quot;。他的诗词展现了超然的人生态度。</p><p><strong>适用主题</strong>: 乐观面对逆境、人生态度、文化自信、精神境界</p><h3 id="樊锦诗-敦煌守护者" tabindex="-1">樊锦诗 - 敦煌守护者 <a class="header-anchor" href="#樊锦诗-敦煌守护者" aria-label="Permalink to &quot;樊锦诗 - 敦煌守护者&quot;">​</a></h3><p><strong>标签</strong>: #文化保护 #坚守 #奉献 #文物保护</p><p><strong>事迹</strong>: 樊锦诗北大毕业后扎根大漠50余年，守护敦煌莫高窟。她推动数字化保护工程，建立&quot;数字敦煌&quot;，让千年文化遗产得以永久保存。</p><p><strong>适用主题</strong>: 坚守、文化传承、奉献精神、择一事终一生</p><h2 id="体育类" tabindex="-1">体育类 <a class="header-anchor" href="#体育类" aria-label="Permalink to &quot;体育类&quot;">​</a></h2><h3 id="苏炳添-亚洲飞人" tabindex="-1">苏炳添 - 亚洲飞人 <a class="header-anchor" href="#苏炳添-亚洲飞人" aria-label="Permalink to &quot;苏炳添 - 亚洲飞人&quot;">​</a></h3><p><strong>标签</strong>: #体育 #突破 #自律 #极限</p><p><strong>事迹</strong>: 苏炳添在东京奥运会男子100米半决赛中跑出9秒83，打破亚洲纪录，成为首位闯入奥运会男子百米决赛的中国选手。32岁依然不断突破自我。</p><p><strong>适用主题</strong>: 突破极限、自律精神、年龄不是界限、中国速度</p><h3 id="全红婵-跳水天才" tabindex="-1">全红婵 - 跳水天才 <a class="header-anchor" href="#全红婵-跳水天才" aria-label="Permalink to &quot;全红婵 - 跳水天才&quot;">​</a></h3><p><strong>标签</strong>: #体育 #天赋 #努力 #拼搏</p><p><strong>事迹</strong>: 全红婵14岁夺得东京奥运会女子10米跳台冠军，以466.20分的总成绩创造历史。她的成功源于日复一的刻苦训练和对完美的追求。</p><p><strong>适用主题</strong>: 天赋与努力、青春拼搏、专注、精益求精</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>选择与论点高度相关的人物素材</li><li>注意素材的时效性，适当使用当代人物</li><li>人物事迹要准确，不可道听途说</li><li>结合具体细节，增强说服力</li><li>一个人物可从多个角度解读，灵活使用</li></ol>',40),s=[n];function i(l,h,p,d,g,c){return t(),r("div",null,s)}const b=a(e,[["render",i]]);export{q as __pageData,b as default};
